mapper.select:

where ai_task_id = #{aiTaskId}
  and run_id = (
      select latest.run_id
      from audit_ai_flow_stage latest
      where latest.ai_task_id = #{aiTaskId}
      order by latest.create_time desc, latest.stage_id desc
      limit 1
  )
order by sort_num asc, stage_id asc


where ai_task_id = #{aiTaskId}
  and run_id = #{runId}
order by sort_num asc, stage_id asc

select count(1)
from audit_ai_flow_stage
where ai_task_id = #{aiTaskId}
  and run_id = #{runId}

mapper.delete:
delete from audit_ai_flow_stage
where ai_task_id = #{aiTaskId}
  and run_id = #{runId}
